mapper.select:
SELECT

FROM recovery_litigation_ext t0


    AND t0.create_stamp BETWEEN

      #{item}



    AND t0.id = #{request.id}


    AND t0.tenant_id = #{request.tenantId}


    AND t0.creator = #{request.creator}


    AND t0.create_stamp = #{request.createStamp}


    AND t0.last_editor = #{request.lastEditor}


    AND t0.last_edit_stamp = #{request.lastEditStamp}


    AND t0.remarks = #{request.remarks}


    AND t0.back_compensation_amount = #{request.backCompensationAmount}


    AND t0.back_interest = #{request.backInterest}


    AND t0.back_liquidated_damages = #{request.backLiquidatedDamages}


    AND t0.back_other_fees = #{request.backOtherFees}


    AND t0.adjust_trial_date = #{request.adjustTrialDate}


    AND t0.adjust_code = #{request.adjustCode}


    AND t0.filing_court_name = #{request.filingCourtName}


    AND t0.judge_name = #{request.judgeName}


    AND t0.filling_date = #{request.fillingDate}


    AND t0.litigation_type = #{request.litigationType}


    AND t0.filling_code = #{request.fillingCode}


    AND t0.judge_date = #{request.judgeDate}


    AND t0.court_session_date = #{request.courtSessionDate}




    ORDER BY ${request.field} ${request.order}


    ORDER BY t0.id DESC
